            aOrbiterH = RotL64((aOrbiterH * 0xB715D58649D4D6EFULL), 51U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterK) + 0x76C90BC297F61F5EULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0x45E0F6E6D3416569ULL;
