            //
            aOrbiterH = ((aOrbiterH + aOrbiterD) + 0x8812966BF8C1CA93ULL) + aPhaseEOrbiterUpdateSaltC[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterI = ((aOrbiterI ^ aOrbiterH) ^ 0xF51B4D0FC3615058ULL) ^ aPhaseEOrbiterUpdateSaltF[((aIndex + 23U)) & S_SALT1];
