            aOrbiterC = (((aWandererI + RotL64(aScatter, 43U)) + RotL64(aCarry, 41U)) + 0x8C846A12F31399AEULL) + aPhaseDOrbiterAssignSaltB[(((31U - aIndex) + 7U)) & S_SALT1];
