            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x7ED210A3C5398749ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 0x582398932F11EB61ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xA739050436059ADFULL), 47U);
