            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererJ = aWandererJ ^ ((RotL64(aIngress, 26U) + aOrbiterD) + RotL64(aOrbiterB, 47U));
            aWandererC = aWandererC + ((RotL64(aCross, 35U) + RotL64(aOrbiterG, 27U)) + aOrbiterK);
            aWandererH = aWandererH ^ ((RotL64(aPrevious, 47U) + aOrbiterK) + RotL64(aOrbiterA, 29U));
