            //
            aOrbiterC = (aOrbiterC + aOrbiterI) + 0xAAF215F4CD67BDC0ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 0xF2E72A16BB35A691ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xBB2B34BB31C4BBCBULL), 23U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 0x4B0FD60E1C0440CAULL;
