            aOrbiterE = (aWandererI + RotL64(aPrevious, 19U)) + 0x060E474C1B11D0EFULL;
            aOrbiterD = (aWandererD + RotL64(aIngress, 41U)) + 0x57B32FC6C7529C75ULL;
